demo.code:
package main

import "fmt"

type User struct {
	Name  string
	Score int
}

func (u User) Label() string {
	return fmt.Sprintf("%s: %d", u.Name, u.Score)
}

func main() {
	u := User{Name: "Ari", Score: 10}
	fmt.Println(u.Label())
}

